Works with any model that can return structured JSON (GPT-4o, Gemini, Claude).
This example uses the OpenAI client but the pattern is provider-agnostic.
"""
from __future__ import annotations
import base64
import io
import json
from dataclasses import dataclass
from typing import Literal

from openai import OpenAI
from PIL import ImageGrab
import pyautogui

