# --- Action schema ---

@dataclass
class ClickAction:
    type: Literal["click"]
    x: int
    y: int
    button: str = "left"

@dataclass
class TypeAction:
    type: Literal["type"]
    text: str

@dataclass
class KeyAction:
    type: Literal["key"]
    key: str

@dataclass
class DoneAction:
    type: Literal["done"]
    result: str


ACTION_SCHEMA = """
Return ONLY valid JSON with one of these shapes:
  {"type": "click", "x": <int>, "y": <int>, "button": "left"|"right"}
  {"type": "type", "text": "<string>"}
  {"type": "key", "key": "<pyautogui key name>"}
  {"type": "done", "result": "<final answer or summary>"}
Do not include explanation outside the JSON object.
"""

SYSTEM_PROMPT = (
    "You are a GUI automation agent. You receive a screenshot and a task. "
    "Reason about what you see, then return the next action as JSON. "
    + ACTION_SCHEMA
)


def capture_b64(width: int = 1280, height: int = 800) -> str:
    img = ImageGrab.grab().resize((width, height))
    buf = io.BytesIO()
    img.save(buf, "JPEG", quality=85)
    return base64.standard_b64encode(buf.getvalue()).decode()


